func keydownHandler(active []db.Task, completed []db.Task) string {
	total := len(active) + len(completed)
	maxIndex := total - 1
	if maxIndex < 0 {
		maxIndex = 0
	}

	return fmt.Sprintf(`
      if ($showForm) {
        if (event.key === 'Escape') {
          event.preventDefault()
          $showForm = false
        }
        return
      }

      if (event.key === 'j') {
        event.preventDefault()
        $selectedIndex = Math.min($selectedIndex + 1, %d)
      }
      if (event.key === 'k') {
        event.preventDefault()
        $selectedIndex = Math.max($selectedIndex - 1, 0)
      }
      if (event.key === ' ') {
        event.preventDefault()
        const items = document.querySelectorAll('#tasks li')
        const el = items[$selectedIndex]
        if (el) {
          el.querySelectorAll('[data-toggle]')[0].click()
        }
      }
      if (event.key === 'y') {
        const items = document.querySelectorAll('#tasks li')
        const el = items[$selectedIndex]
        if (el) {
          const title = el.querySelector('.task-title').textContent
          navigator.clipboard.writeText(title)
        }
      }
      if (event.key === 'i') {
        event.preventDefault()
        $showForm = true
        setTimeout(function() { document.getElementById('new-task').focus() }, 0)
      }
      if (event.key === 'x') {
        $hideCompleted = !$hideCompleted
      }
      if (event.key === 'd') {
      if (window._pendingD) {
        clearTimeout(window._pendingD)
          window._pendingD = null
          const items = document.querySelectorAll('#tasks li')
          const el = items[$selectedIndex]
          if (el) {
            el.querySelector('button:last-child').click()
          }
      } else {
        window._pendingD = setTimeout(function() {
            window._pendingD = null
            }, 500)
      }
}
    `, maxIndex)
}

func formatTime(t pgtype.Timestamp) string {
	if !t.Valid {
		return ""
	}
	return t.Time.Format("Jan 2 3:04 PM")
}

func completedClass(done bool) string {
	if done {
		return "completed"
	}
	return ""
}

